import android.content.Context
import android.content.Intent
import android.content.SharedPreferences
import android.os.Bundle
import android.provider.Settings
import android.widget.Button
import android.widget.TextView
import android.widget.Toast
import androidx.appcompat.app.AppCompatActivity
import androidx.biometric.BiometricManager
import androidx.biometric.BiometricPrompt
import androidx.core.content.ContextCompat

// LoginActivity.kt
class LoginActivity : AppCompatActivity() {

    private lateinit var biometricPrompt: BiometricPrompt
    private lateinit var promptInfo: BiometricPrompt.PromptInfo
    private lateinit var sharedPreferences: SharedPreferences

    private lateinit var btnBiometricLogin: Button
    private lateinit var btnPasswordLogin: Button
    private lateinit var tvStatus: TextView

    companion object {
        const val PREFS_NAME = "AuthPrefs"
        const val KEY_AUTHENTICATED = "isAuthenticated"
    }

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_login)

        sharedPreferences = getSharedPreferences(PREFS_NAME, Context.MODE_PRIVATE)

        btnBiometricLogin = findViewById(R.id.btnBiometricLogin)
        btnPasswordLogin = findViewById(R.id.btnPasswordLogin)
        tvStatus = findViewById(R.id.tvStatus)

        // Check if already authenticated (e.g., from a previous session)
        if (sharedPreferences.getBoolean(KEY_AUTHENTICATED, false)) {
            navigateToMainActivity()
            return
        }

        setupBiometricPrompt() // Initialize BiometricPrompt before it's potentially needed

        btnBiometricLogin.setOnClickListener {
            showBiometricPrompt()
        }

        btnPasswordLogin.setOnClickListener {
            authenticateWithPassword()
        }
    }

    override fun onResume() {
        super.onResume()
        // Re-check biometric status in case user enrolled/disabled biometrics in settings
        checkBiometricAvailability()
    }

    private fun checkBiometricAvailability() {
        val biometricManager = BiometricManager.from(this)
        when (biometricManager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)) {
            BiometricManager.BIOMETRIC_SUCCESS -> {
                tvStatus.text = "You can use fingerprint to log in."
                btnBiometricLogin.isEnabled = true
            }
            BiometricManager.BIOMETRIC_ERROR_NO_HARDWARE -> {
                tvStatus.text = "No biometric features available on this device."
                btnBiometricLogin.isEnabled = false
            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                tvStatus.text = "Biometric features are currently unavailable."
                btnBiometricLogin.isEnabled = false
            }
            BiometricManager.BIOMETRIC_ERROR_NONE_ENROLLED -> {
                tvStatus.text = "No fingerprint enrolled. Please enroll fingerprints in settings."
                btnBiometricLogin.isEnabled = false
                // Suggest user to enroll biometrics
                // For Android 11+
                if (android.os.Build.VERSION.SDK_INT >= android.os.Build.VERSION_CODES.R) {
                    val enrollIntent = Intent(Settings.ACTION_BIOMETRIC_ENROLL).apply {
                        putExtra(Settings.EXTRA_BIOMETRIC_AUTHENTICATORS_ALLOWED,
                            BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)
                    }
                    startActivity(enrollIntent)
                } else {
                    // For earlier Android versions, direct user to security settings
                    startActivity(Intent(Settings.ACTION_SECURITY_SETTINGS))
                }
            }
            else -> {
                tvStatus.text = "Biometric features are not available or not set up correctly."
                btnBiometricLogin.isEnabled = false
            }
        }
    }

    private fun setupBiometricPrompt() {
        val executor = ContextCompat.getMainExecutor(this)

        biometricPrompt = BiometricPrompt(this, executor,
            object : BiometricPrompt.AuthenticationCallback() {
                override fun onAuthenticationError(errorCode: Int, errString: CharSequence) {
                    super.onAuthenticationError(errorCode, errString)
                    tvStatus.text = "Authentication error: $errString"
                    Toast.makeText(applicationContext, "Authentication error: $errString", Toast.LENGTH_SHORT).show()
                    // Fallback to password login explicitly if biometrics fail (e.g., user clicked "Use password" or too many attempts)
                    if (errorCode == BiometricPrompt.ERROR_NEGATIVE_BUTTON) {
                         // User explicitly chose to use password
                         Toast.makeText(applicationContext, "Please use your account password.", Toast.LENGTH_LONG).show()
                    } else {
                         // Other errors (e.g., too many attempts, hardware issue)
                         Toast.makeText(applicationContext, "Biometric login failed. Please try password login.", Toast.LENGTH_LONG).show()
                    }
                    btnPasswordLogin.text = "Continue with Password" // Hint user to use password
                }

                override fun onAuthenticationSucceeded(result: BiometricPrompt.AuthenticationResult) {
                    super.onAuthenticationSucceeded(result)
                    tvStatus.text = "Authentication succeeded!"
                    Toast.makeText(applicationContext, "Authentication succeeded!", Toast.LENGTH_SHORT).show()
                    saveAuthStatus(true)
                    navigateToMainActivity()
                }

                override fun onAuthenticationFailed() {
                    super.onAuthenticationFailed()
                    tvStatus.text = "Authentication failed. Try again."
                    Toast.makeText(applicationContext, "Authentication failed. Try again.", Toast.LENGTH_SHORT).show()
                }
            })

        promptInfo = BiometricPrompt.PromptInfo.Builder()
            .setTitle("Fingerprint Login")
            .setSubtitle("Log in using your fingerprint credential")
            .setNegativeButtonText("Use Account Password") // This offers the fallback within the prompt itself
            .setAllowedAuthenticators(BiometricManager.Authenticators.BIOMETRIC_STRONG or BiometricManager.Authenticators.BIOMETRIC_WEAK)
            .build()
    }

    private fun showBiometricPrompt() {
        biometricPrompt.authenticate(promptInfo)
    }

    private fun authenticateWithPassword() {
        // In a real app, this would navigate to a password input screen
        // For this example, we'll simulate a successful password login.
        Toast.makeText(this, "Simulating password login success.", Toast.LENGTH_SHORT).show()
        saveAuthStatus(true)
        navigateToMainActivity()
    }

    private fun saveAuthStatus(isAuthenticated: Boolean) {
        sharedPreferences.edit().putBoolean(KEY_AUTHENTICATED, isAuthenticated).apply()
    }

    private fun navigateToMainActivity() {
        val intent = Intent(this, MainActivity::class.java)
        startActivity(intent)
        finish() // Prevent going back to login screen with back button
    }
}

// MainActivity.kt
class MainActivity : AppCompatActivity() {

    private lateinit var sharedPreferences: SharedPreferences

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        sharedPreferences = getSharedPreferences(LoginActivity.PREFS_NAME, Context.MODE_PRIVATE)

        val tvWelcome = findViewById<TextView>(R.id.tvWelcome)
        tvWelcome.text = "Welcome! You are authenticated."

        val btnLogout = findViewById<Button>(R.id.btnLogout)
        btnLogout.setOnClickListener {
            logout()
        }
    }

    private fun logout() {
        sharedPreferences.edit().putBoolean(LoginActivity.KEY_AUTHENTICATED, false).apply()
        val intent = Intent(this, LoginActivity::class.java)
        startActivity(intent)
        finish() // Prevent going back to main activity with back button
    }
}

